import torch
from torch import nn
from torch.nn import functional as F
from einops import rearrange


# %% ../../nbs/02c_models.jepa.ipynb #776969f1
def modulate(x, shift, scale):
    """AdaLN-zero modulation"""
    return x * (1 + scale) + shift

def csi_to_features(csi: torch.Tensor, eps: float = 1e-6) -> torch.Tensor:
    """
    csi: (B, T) complex tensor, single-antenna channel coefficient
    returns: (B, T, 3) real feature tensor [log|h|, sin(angle), cos(angle)]
    """
    mag = csi.abs()
    log_mag = torch.log(mag + eps)
    angle = csi.angle()
    return torch.stack([log_mag, angle.sin(), angle.cos()], dim=-1)


# %% ../../nbs/02c_models.jepa.ipynb #3965d6fd
class SIGReg(torch.nn.Module):
    """Sketch Isotropic Gaussian Regularizer (single-GPU!)"""

    def __init__(self, knots=17, num_proj=1024):
        super().__init__()
        self.num_proj = num_proj
        t = torch.linspace(0, 3, knots, dtype=torch.float32)
        dt = 3 / (knots - 1)
        weights = torch.full((knots,), 2 * dt, dtype=torch.float32)
        weights[[0, -1]] = dt
        window = torch.exp(-t.square() / 2.0)
        self.register_buffer("t", t)
        self.register_buffer("phi", window)
        self.register_buffer("weights", weights * window)

    def forward(self, proj):
        """
        proj: (T, B, D)
        """
        # sample random projections
        A = torch.randn(proj.size(-1), self.num_proj, device=proj.device)
        A = A.div_(A.norm(p=2, dim=0))
        # compute the epps-pulley statistic
        x_t = (proj @ A).unsqueeze(-1) * self.t
        err = (x_t.cos().mean(-3) - self.phi).square() + x_t.sin().mean(-3).square()
        statistic = (err @ self.weights) * proj.size(-2)
        return statistic.mean() # average over projections and time
    

