class FeedForward(nn.Module):
    """FeedForward network used in Transformers"""

    def __init__(self, dim, hidden_dim, dropout=0.0):
        super().__init__()
        self.net = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, hidden_dim),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, dim),
            nn.Dropout(dropout),
        )

    def forward(self, x):
        return self.net(x)


# %% ../../nbs/02c_models.jepa.ipynb #295b02b3
class Attention(nn.Module):
    """Scaled dot-product attention with causal masking"""

    def __init__(self, dim, heads=8, dim_head=64, dropout=0.0):
        super().__init__()
        inner_dim = dim_head * heads
        project_out = not (heads == 1 and dim_head == dim)
        self.heads = heads
        self.scale = dim_head**-0.5
        self.dropout = dropout
        self.norm = nn.LayerNorm(dim)
        self.attend = nn.Softmax(dim=-1)
        self.to_qkv = nn.Linear(dim, inner_dim * 3, bias=False)
        self.to_out = (
            nn.Sequential(nn.Linear(inner_dim, dim), nn.Dropout(dropout))
            if project_out
            else nn.Identity()
        )

    def forward(self, x, causal=True):
        """
        x : (B, T, D)
        """
        x = self.norm(x)
        drop = self.dropout if self.training else 0.0
        qkv = self.to_qkv(x).chunk(3, dim=-1)  # q, k, v: (B, heads, T, dim_head)
        q, k, v = (rearrange(t, "b t (h d) -> b h t d", h=self.heads) for t in qkv)
        out = F.scaled_dot_product_attention(q, k, v, dropout_p=drop, is_causal=causal)
        out = rearrange(out, "b h t d -> b t (h d)")
        return self.to_out(out)



# %% ../../nbs/02c_models.jepa.ipynb #4c2495ef
class MessageConditionedBlock(nn.Module):
    def __init__(self, dim, heads, dim_head, mlp_dim, dropout=0.0, csi_feat_dim=3):
        super().__init__()
        self.attn = Attention(dim, heads=heads, dim_head=dim_head, dropout=dropout)
        self.mlp = FeedForward(dim, mlp_dim, dropout=dropout)
        self.norm1 = nn.LayerNorm(dim, elementwise_affine=False, eps=1e-6)
        self.norm2 = nn.LayerNorm(dim, elementwise_affine=False, eps=1e-6)
        self.adaLN_modulation = nn.Sequential(
            nn.SiLU(), nn.Linear(dim, 6 * dim, bias=True)
        )
        nn.init.constant_(self.adaLN_modulation[-1].weight, 0)
        nn.init.constant_(self.adaLN_modulation[-1].bias, 0)

        self.cross_attn = nn.MultiheadAttention(
            embed_dim=dim, num_heads=heads, batch_first=True, dropout=dropout
        )
        self.cross_norm = nn.LayerNorm(dim)

        # csi_feat_dim = width of the *preprocessed real* CSI features (e.g. 3 for [log|h|, sin, cos])
        self.csi_proj = nn.Sequential(
            nn.Linear(csi_feat_dim, dim), nn.SiLU(), nn.Linear(dim, dim)
        )

        self.msg_gate = nn.Sequential(
            nn.Linear(dim * 2, 1),
            nn.Sigmoid()
        )

    def forward(self, x, c, msg_tokens=None, csi_feat=None, return_attention=False):
        shift_msa, scale_msa, gate_msa, shift_mlp, scale_mlp, gate_mlp = (
            self.adaLN_modulation(c).chunk(6, dim=-1)
        )
        x = x + gate_msa * self.attn(modulate(self.norm1(x), shift_msa, scale_msa))

        attn_weights, gate = None, None
        if msg_tokens is not None:
            B, T, N, D = msg_tokens.shape
            msg_seq = msg_tokens.reshape(B, T * N, D)

            mask = torch.ones(T, T * N, dtype=torch.bool, device=x.device)
            for t in range(T):
                mask[t, :(t + 1) * N] = False

            msg_attended, attn_weights = self.cross_attn(
                query=self.cross_norm(x),
                key=msg_seq,
                value=msg_seq,
                attn_mask=mask,
                need_weights=True
            )

            if csi_feat is not None:
                csi_emb = self.csi_proj(csi_feat)      # (B, T, D), csi_feat already real-valued
            else:
                csi_emb = torch.zeros_like(x)

            gate = self.msg_gate(torch.cat([x, csi_emb], dim=-1))
            x = x + gate * msg_attended

        x = x + gate_mlp * self.mlp(modulate(self.norm2(x), shift_mlp, scale_mlp))

        if return_attention:
            return x, attn_weights, gate
        return x
    

