class ARPredictor(nn.Module):
    def __init__(
        self,
        *,
        num_frames,
        depth,
        heads,
        mlp_dim,
        input_dim,
        hidden_dim,
        output_dim=None,
        dim_head=64,
        dropout=0.0,
        emb_dropout=0.0,
        msg_embedding_dim=256,   # VQ-VAE embedding_dim
        num_embeddings=256,      # VQ-VAE codebook size
        num_msg_tokens=49,       # spatial grid size (7x7), no longer hardcoded
    ):
        super().__init__()
        self.pos_embedding = nn.Parameter(torch.randn(1, num_frames, input_dim))
        self.dropout = nn.Dropout(emb_dropout)

        self.msg_proj = (
            nn.Linear(msg_embedding_dim, hidden_dim)
            if msg_embedding_dim != hidden_dim
            else nn.Identity()
        )

        self.msg_token_embedding = nn.Embedding(
            num_embeddings + 1, msg_embedding_dim, padding_idx=num_embeddings
        )

        # NEW: positional embeddings for message tokens
        self.num_msg_tokens = num_msg_tokens
        self.msg_pos_spatial = nn.Parameter(torch.randn(1, 1, num_msg_tokens, hidden_dim) * 0.02)
        self.msg_pos_temporal = nn.Parameter(torch.randn(1, num_frames, 1, hidden_dim) * 0.02)

        self.transformer = Transformer(
            input_dim,
            hidden_dim,
            output_dim or input_dim,
            depth,
            heads,
            dim_head,
            mlp_dim,
            dropout,
            block_class=MessageConditionedBlock,
        )

    def forward(self, x, c, msg_indices=None, csi=None, return_attention=False):
        """
        x:           (B, T, D)    — state embeddings
        c:           (B, T, D)    — action embeddings
        msg_indices: (B, T, 49)   — VQ token indices from sender, optional
        csi:         (B, T)       — complex tensor, single-antenna channel coefficient — raw from Sionna
        """
        T = x.size(1)
        x = x + self.pos_embedding[:, :T]
        x = self.dropout(x)

        m = None
        if msg_indices is not None:
            msg_indices = rearrange(msg_indices, "b t n -> (b t) n")
            m = self.msg_token_embedding(msg_indices)   # (B*T, 49, msg_embedding_dim)
            m = self.msg_proj(m)               # (B*T, 49, D)
            m = rearrange(m, "(b t) n d -> b t n d", b=x.size(0), t=T)

            # NEW: add spatial + temporal position embeddings
            m = m + self.msg_pos_spatial + self.msg_pos_temporal[:, :T]

        if return_attention:
            x, attn_weights, gates = self.transformer(
                x, c, msg_tokens=m, return_attention=True
            )
            return x, attn_weights, gates
        
        csi_feat = csi_to_features(csi) if csi is not None else None
        x = self.transformer(x, c, msg_tokens=m, csi_feat=csi_feat)
        return x
    

