"""JEPA Implementation"""

def detach_clone(v):
    return v.detach().clone() if torch.is_tensor(v) else v

class JEPA(nn.Module):

    def __init__(
        self,
        encoder,
        predictor,
        action_encoder,
        projector=None,
        pred_proj=None,
        **kwargs
    ):
        super().__init__()

        self.encoder = encoder
        self.predictor = predictor
        self.action_encoder = action_encoder
        self.projector = projector or nn.Identity()
        self.pred_proj = pred_proj or nn.Identity()
        self.sigreg = SIGReg(knots=17, num_proj=1024)

    def encode(self, info):
        """Encode observations and actions into embeddings.
        info: dict with pixels and action keys
        """
        pixels = info['pixels']
        b = pixels.size(0)
        pixels = rearrange(pixels, "b t ... -> (b t) ...") # flatten for encoding
        output = self.encoder(pixels, interpolate_pos_encoding=True)
        pixels_emb = output.last_hidden_state[:, 0]  # cls token
        emb = self.projector(pixels_emb)
        info["emb"] = rearrange(emb, "(b t) d -> b t d", b=b)

        if "action" in info:
            info["act_emb"] = self.action_encoder(info["action"])#.to(device))

        return info

    def predict(self, emb, act_emb, msg_indices=None, csi=None):
        """Predict next state embedding
        emb: (B, T, D) 
        act_emb: (B, T, A_emb)
        msg_indices: (B, T, 49)
        csi: (B, T) complex tensor, single-antenna channel coefficient, optional
        """
        preds = self.predictor(emb, act_emb, msg_indices=msg_indices, csi=csi)
        preds = self.pred_proj(rearrange(preds, "b t d -> (b t) d"))
        preds = rearrange(preds, "(b t) d -> b t d", b=emb.size(0))
        return preds
    

    def loss_fn(self, output, pred_emb, target_emb, emb, lambd):
        output["pred_loss"] = (pred_emb - target_emb).pow(2).mean()
        output["sigreg_loss"]= self.sigreg(emb.transpose(0, 1))
        output["jepa_loss"] = output["pred_loss"] + lambd * output["sigreg_loss"] 
        return output

    ####################
    ## Inference only ##
    ####################

    
    def rollout(self, info, action_sequence, history_size: int = 3, num_embeddings=256):
        """Rollout the model given an initial info dict and action sequence.
        pixels: (B, S, T, C, H, W)
        action_sequence: (B, S, T, action_dim)
        msg_indices: (B, S, 1, 49) VQ token indices from sender, optional
        csi: (B, S, 1) complex tensor, single-antenna channel coefficient, optional
        - S is the number of action plan samples
        - T is the time horizon
        """

        assert "pixels" in info, "pixels not in info_dict"
        H = info["pixels"].size(2)
        B, S, T = action_sequence.shape[:3]
        act_0, act_future = torch.split(action_sequence, [H, T - H], dim=2)
        info["action"] = act_0
        n_steps = T - H

        _init = {k: v[:, 0] for k, v in info.items() if torch.is_tensor(v)}
        _init = self.encode(_init)
        emb = info["emb"] = _init["emb"].unsqueeze(1).expand(B, S, -1, -1)
        _init = {k: detach_clone(v) for k, v in _init.items()}

        emb = rearrange(emb, "b s ... -> (b s) ...").clone()
        act = rearrange(act_0, "b s ... -> (b s) ...")
        act_future = rearrange(act_future, "b s ... -> (b s) ...")

        HS = history_size
        for t in range(n_steps):
            if t > 0:
                step_msg_indices = None
                step_csi = None                    # NEW: no channel reading for imagined steps
            else:
                step_msg_indices = info.get("msg_indices", None)
                step_csi = info.get("csi", None)    # NEW

                if step_msg_indices is not None:
                    step_msg_indices = rearrange(step_msg_indices, "b s o n -> (b s) o n")

                    pad_steps = HS - step_msg_indices.size(1)
                    pad = torch.full(
                        (step_msg_indices.size(0), pad_steps, step_msg_indices.size(2)),
                        fill_value=num_embeddings,
                        dtype=step_msg_indices.dtype,
                        device=step_msg_indices.device,
                    )
                    step_msg_indices = torch.cat([pad, step_msg_indices], dim=1)  # (BS, HS, 49)

                if step_csi is not None:                                          # NEW block
                    step_csi = rearrange(step_csi.squeeze(-1), "b s o -> (b s) o")
                    pad_steps = HS - step_csi.size(1)
                    # zero complex value = no channel reading; note this naturally maps to a very
                    # negative log-magnitude in csi_to_features, i.e. "worst-case" channel, which
                    # is a sensible default for "no real message was present at this history step"
                    csi_pad = torch.zeros(
                        step_csi.size(0), pad_steps,
                        dtype=step_csi.dtype, device=step_csi.device,
                    )
                    step_csi = torch.cat([csi_pad, step_csi], dim=1)  # (BS, HS)

            act_emb = self.action_encoder(act)
            emb_trunc = emb[:, -HS:]
            act_trunc = act_emb[:, -HS:]
            pred_emb = self.predict(emb_trunc, act_trunc, step_msg_indices, step_csi)[:, -1:]  # NEW: pass csi
            emb = torch.cat([emb, pred_emb], dim=1)

            next_act = act_future[:, t : t + 1]
            act = torch.cat([act, next_act], dim=1)

        act_emb = self.action_encoder(act)
        emb_trunc = emb[:, -HS:]
        act_trunc = act_emb[:, -HS:]
        pred_emb = self.predict(emb_trunc, act_trunc)[:, -1:]  # no msg_indices, no csi — correct, matches existing behavior
        emb = torch.cat([emb, pred_emb], dim=1)

        pred_rollout = rearrange(emb, "(b s) ... -> b s ...", b=B, s=S)
        info["predicted_emb"] = pred_rollout

        return info


    def criterion(self, info_dict: dict):
        """Compute the cost between predicted embeddings and goal embeddings."""
        pred_emb = info_dict["predicted_emb"]  # (B,S, T-1, dim)
        goal_emb = info_dict["goal_emb"]  # (B, S, T, dim)

        goal_emb = goal_emb[..., -1:, :].expand_as(pred_emb)

        # return last-step cost per action candidate
        cost = F.mse_loss(
            pred_emb[..., -1:, :],
            goal_emb[..., -1:, :].detach(),
            reduction="none",
        ).sum(dim=tuple(range(2, pred_emb.ndim)))  # (B, S)

        return cost

    def get_cost(self, info_dict: dict, action_candidates: torch.Tensor):
        """ Compute the cost of action candidates given an info dict with goal and initial state."""

        assert "goal" in info_dict, "goal not in info_dict"

        device = next(self.parameters()).device
        for k in list(info_dict.keys()):
            if torch.is_tensor(info_dict[k]):
                info_dict[k] = info_dict[k].to(device)

        goal = {k: v[:, :1] for k, v in info_dict.items() if torch.is_tensor(v)}
        goal["pixels"] = goal["goal"]

        for k in info_dict:
            if k.startswith("goal_"):
                goal[k[len("goal_") :]] = goal.pop(k)

        goal.pop("action")
        goal = self.encode(goal)
        info_dict["goal_emb"] = goal["emb"].unsqueeze(2)  # (B, S=1, T=1, D) — ready to broadcast in criterion
        info_dict = self.rollout(info_dict, action_candidates)

        cost = self.criterion(info_dict)
        
        return cost
    
